const t=document.createElement("script");t.src=chrome.runtime.getURL("inpage.js");t.onload=()=>t.remove();(document.head||document.documentElement).appendChild(t);window.addEventListener("message",async n=>{var i;if(n.source!==window||((i=n.data)==null?void 0:i.type)!=="SOLEN_REQUEST")return;const{id:a,method:r,params:o}=n.data,s=window.location.origin;try{let e;switch(r){case"connect":e=await chrome.runtime.sendMessage({type:"DAPP_CONNECT",origin:s});break;case"getAccounts":e=await chrome.runtime.sendMessage({type:"DAPP_GET_ACCOUNTS",origin:s});break;case"signAndSubmit":e=await chrome.runtime.sendMessage({type:"DAPP_SIGN_AND_SUBMIT",origin:s,operation:o});break;case"signMessage":e=await chrome.runtime.sendMessage({type:"DAPP_SIGN_MESSAGE",origin:s,message:o.message});break;default:e={error:`Unknown method: ${r}`}}window.postMessage({type:"SOLEN_RESPONSE",id:a,result:e},"*")}catch(e){window.postMessage({type:"SOLEN_RESPONSE",id:a,error:e instanceof Error?e.message:"Extension error"},"*")}});
